import pytest
import requests

def test_create_benefit_unauthenticated_returns_401(base_url, unique_benefit_name):
    payload = {
        "name": unique_benefit_name(),
        "type": "health",
        "description": "No auth header",
        "effective_date": "2024-01-01"
    }
    headers = {"Content-Type": "application/json"}

    resp = requests.post(f"{base_url}/api/benefits", json=payload, headers=headers)

    assert resp.status_code == 401, f"Expected 401 but got {resp.status_code} {resp.text}"

import pytest
import requests

def test_create_benefit_forbidden_role_returns_403(base_url, get_employee_token, unique_benefit_name):
    token = get_employee_token()
    payload = {
        "name": unique_benefit_name(),
        "type": "health",
        "description": "Employee should not create benefits",
        "effective_date": "2024-01-01"
    }
    headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}

    resp = requests.post(f"{base_url}/api/benefits", json=payload, headers=headers)

    assert resp.status_code == 403, f"Expected 403 but got {resp.status_code} {resp.text}"
